INSERT INTO `wp_comments` VALUES (1, 1, 'Un comentarista de WordPress', 'wapuu@wordpress.example', 'https://ve.wordpress.org/', '', '2022-05-31 10:15:46', '2022-05-31 14:15:46', 'Hola, esto es un comentario.\nPara empezar a moderar, editar y borrar comentarios, por favor, visita en el escritorio la pantalla de comentarios.\nLos avatares de los comentaristas provienen de <a href=\"https://es.gravatar.com/\">Gravatar</a>.', 0, 'post-trashed', '', 'comment', 0, 0);
