ntainer-51 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-51 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-51 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style></div>\n<style>.wp-container-52 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-52 > * { margin: 0; }</style>\n\n\n<div class=\"wp-container-56 wp-block-columns alignwide\">\n<div class=\"wp-container-53 wp-block-column\" style=\"flex-basis:33.38%\">\n<p class=\"has-text-color has-extra-small-font-size\" style=\"color:#000000\"><em>Naturaleza</em>, en el sentido habitual, se refiere a las esencias inalteradas por el hombre; el espacio, el aire, el río, la hoja.&nbsp;<em>Arte</em>&nbsp;se aplica a la mezcla de su voluntad con las mismas cosas, como en una casa, un canal, una estatua, un cuadro. Pero sus operaciones tomadas en conjunto son tan insignificantes, un poco de astillado, horneado, remiendo y lavado, que en una impresión tan grandiosa como la del mundo en la mente humana, no varían el resultado.</p>\n</div>\n<style>.wp-container-53 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-53 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-53 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-53 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-53 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style>\n\n\n<div class=\"wp-container-54 wp-block-column\" style=\"flex-basis:33%\">\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img src=\"https://s.w.org/images/core/5.8/outside-01.jpg\" alt=\"La puesta de sol a través de un denso bosque.\" /></figure>\n</div>\n<style>.wp-container-54 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-54 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-54 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-54 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-54 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style>\n\n\n<div class=\"wp-container-55 wp-block-column\" style=\"flex-basis:33.62%\">\n<figure class=\"wp-block-image size-large\"><img src=\"https://s.w.org/images/core/5.8/outside-02.jpg\" alt=\"Aerogeneradores en una llanura de hierba, con un cielo azul.\" /></figure>\n</div>\n<style>.wp-container-55 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-55 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-55 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-55 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-55 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style></div>\n<style>.wp-container-56 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-56 > * { margin: 0; }</style>\n\n\n<div class=\"wp-container-59 wp-block-columns alignwide\">\n<div class=\"wp-container-57 wp-block-column\" style=\"flex-basis:67%\">\n<div class=\"wp-block-image\"><figure class=\"alignright size-large\"><img src=\"https://s.w.org/images/core/5.8/outside-03.jpg\" alt=\"El sol brilla sobre una cresta que desciende hacia la costa. A lo lejos, un coche circula por una carretera.\" /></figure></div>\n</div>\n<style>.wp-container-57 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-57 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-57 > .aligncente