1.3\"}}} -->\n<h3 style=\"font-size:24px;line-height:1.3\"><strong><a href=\"https://wordpress.org\">Current Shows ↗</a></strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Stay updated and see our current exhibitions here.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:heading {\"level\":3,\"style\":{\"typography\":{\"fontSize\":\"24px\",\"lineHeight\":\"1.3\"}}} -->\n<h3 style=\"font-size:24px;line-height:1.3\"><strong><a href=\"https://wordpress.org\">Useful Info ↗</a></strong></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Get to know our opening times, ticket prices and discounts.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\";}i:27;O:8:\"stdClass\":7:{s:2:\"id\";i:199;s:5:\"title\";O:8:\"stdClass\":1:{s:8:\"rendered\";s:34:\"Three columns with images and text\";}s:7:\"content\";O:8:\"stdClass\":2:{s:8:\"rendered\";s:6557:\"\n<div class=\"wp-container-128 wp-block-group alignfull has-background\" style=\"background-color:#f8f4e4\">\n<div class=\"wp-container-120 wp-block-columns alignwide\">\n<div class=\"wp-container-119 wp-block-column\">\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<h6 class=\"has-text-color\" id=\"ecosystem\" style=\"color:#000000\">ECOSYSTEM</h6>\n\n\n\n<p class=\"has-text-color\" style=\"color:#000000;font-size:5vw;line-height:1.1\"><strong>Positive growth.</strong></p>\n\n\n\n<div style=\"height:5px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n</div>\n<style>.wp-container-119 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-119 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-119 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-119 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-119 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style></div>\n<style>.wp-container-120 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-120 > * { margin: 0; }</style>\n\n\n<div class=\"wp-container-124 wp-block-columns alignwide\">\n<div class=\"wp-container-121 wp-block-column\" style=\"flex-basis:33.38%\">\n<p class=\"has-text-color has-extra-small-font-size\" style=\"color:#000000\"><em>Nature</em>, in the common sense, refers to essences unchanged by man; space, the air, the river, the leaf.&nbsp;<em>Art</em>&nbsp;is applied to the mixture of his will with the same things, as in a house, a canal, a statue, a picture. But his operations taken together are so insignificant, a little chipping, baking, patching, and washing, that in an impression so grand as that of the world on the human mind, they do not vary the result.</p>\n</div>\n<style>.wp-container-121 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-121 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-121 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-121 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-121 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style>\n\n\n<div class=\"wp-container-122 wp-block-column\" style=\"flex-basis:33%\">\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img src=\"https://s.w.org/images/core/5.8/outside-01.jpg\" alt=\"The sun setting through a dense forest.\" /></figure>\n</div>\n<style>.wp-container-122 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-122 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-122 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-122 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-122 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style>\n\n\n<div class=\"wp-container-123 wp-block-column\" style=\"flex-basis:33.62%\">\n<figure class=\"wp-block-image size-large\"><img src=\"https://s.w.org/images/core/5.8/outside-02.jpg\" alt=\"Wind turbines standing on a grassy plain, against a blue sky.\" /></figure>\n</div>\n<style>.wp-container-123 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-123 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-123 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-123 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-123 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style></div>\n<style>.wp-container-124 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-124 > * { margin: 0; }</style>\n\n\n<div class=\"wp-container-127 wp-block-columns alignwide\">\n<div class=\"wp-container-125 wp-block-column\" style=\"flex-basis:67%\">\n<div class=\"wp-block-image\"><figure class=\"alignright size-large\"><img src=\"https://s.w.org/images/core/5.8/outside-03.jpg\" alt=\"The sun shining over a ridge leading down into the shore. In the distance, a car drives down a road.\" /></figure></div>\n</div>\n<style>.wp-container-125 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-125 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-125 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-125 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-125 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style>\n\n\n<div class=\"wp-container-126 wp-block-column is-vertically-aligned-center\" style=\"flex-basis:33%\">\n<p class=\"has-text-color has-extra-small-font-size\" style=\"color:#000000\">Undoubtedly we have no questions to ask which are unanswerable. We must trust the perfection of the creation so far, as to believe that whatever curiosity the order of things has awakened in our minds, the order of things can satisfy. Every man&#8217;s condition is a solution in hieroglyphic to those inquiries he would put.</p>\n</div>\n<style>.wp-container-126 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-126 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-126 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-126 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-126 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style></div>\n<style>.wp-container-127 {display: flex;gap: var( --wp--style--block-gap, 0.5em );flex-wrap: nowrap;align-items: center;}.wp-container-127 > * { margin: 0; }</style></div>\n<style>.wp-container-128 > .alignleft { float: left; margin-inline-start: 0; margin-inline-end: 2em; }.wp-container-128 > .alignright { float: right; margin-inline-start: 2em; margin-inline-end: 0; }.wp-container-128 > .aligncenter { margin-left: auto !important; margin-right: auto !important; }.wp-container-128 > * { margin-block-start: 0; margin-block-end: 0; }.wp-container-128 > * + * { margin-block-start: var( --wp--style--block-gap ); margin-block-end: 0; }</style>\";s:9:\"protected\";b:0;}s:4:\"meta\";O:8:\"stdClass\":6:{s:10:\"spay_email\";s:0:\"\";s:13:\"wpop_keywords\";s:0:\"\";s:16:\"wpop_description\";s:77:\"Three columns with images and text, with vertical spacing for an offset look.\";s:19:\"wpop_viewport_width\";i:1200;s:16:\"wpop_block_types\";a:0:{}s:11:\"wpop_locale\";s:5: